let particles = [];
let keys = {};

// Input handling
document.addEventListener('keydown', (e) => {
    keys[e.key.toLowerCase()] = true;
    if (gameRunning) {
        // P1 controls
        if (e.key === 'w' || e.key === 'W') player1.jump();
        if (e.key === 'f' || e.key === 'F') player1.attack(player2);

        // P2 controls
        if (e.key === 'ArrowUp') player2.jump();
        if (e.key === 'l' || e.key === 'L') player2.attack(player1);
    }
});

