Here's the updated code with rainbow animation:

```cpp
/*
 * ESP32-C3 WS2812 RGB LED Strip - Rainbow Animation
 * 
 * Hardware: ESP32-C3 DevKit
 * LED Strip: WS2812 (NeoPixel compatible)
 */

#include <Adafruit_NeoPixel.h>

#define LED_PIN     8
#define NUM_LEDS    30
#define BRIGHTNESS  128

Adafruit_NeoPixel strip(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  Serial.begin(115200);
  strip.begin();
  strip.setBrightness(BRIGHTNESS);
  Serial.println("ESP32-C3 WS2812 - Rainbow Animation");
}

void loop() {
  // Rainbow animation - cycles through all colors
  rainbowCycle(20);  // 20ms delay between steps
}

// Rainbow cycle animation - flowing rainbow across strip
void rainbowCycle(int wait) {
  for (long firstPixelHue = 0; firstPixelHue < 5 * 65536; firstPixelHue += 256) {
    for (int i = 0; i < NUM_LEDS; i++) {
      int pixelHue = firstPixelHue + (i * 65536L / NUM_LEDS);
      strip.setPixelColor(i, strip.gamma32(strip.ColorHSV(pixelHue)));
    }
    strip.show();
    delay(wait);
  }
}

// Static rainbow - all LEDs show different colors
void staticRainbow() {
  for (int i = 0; i < NUM_LEDS; i++) {
    int hue = map(i, 0, NUM_LEDS - 1, 0, 65535);
    strip.setPixelColor(i, strip.gamma32(strip.ColorHSV(hue)));
  }
  strip.show();
}

// Rainbow chase - moving rainbow across strip
void rainbowChase(int wait) {
  for (int j = 0; j < 256; j++) {
    for (int i = 0; i < NUM_LEDS; i++) {
      int hue = ((i * 256 / NUM_LEDS) + j) & 255;
      strip.setPixelColor(i, strip.ColorHSV(hue * 256, 255, 255));
    }
    strip.show();
    delay(wait);
  }
}
```

**Rainbow Functions:**
- `rainbowCycle(20)` - Flowing rainbow animation (smooth color cycle)
- `staticRainbow()` - Static rainbow (each LED different color)
- `rainbowChase(50)` - Chase effect with rainbow colors

The main loop now runs `rainbowCycle(20)` which creates a smooth flowing rainbow effect across the LED strip!

